# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import requests
from requests.auth import HTTPBasicAuth

# Configuration
rabbitmq_url = 'http://localhost:15672/api/'
admin_username = 'admin'
admin_password = 'password'

# Define virtual hosts and user permissions
virtual_hosts = [
    {'name': '/app1', 'user_permissions': [{'username': 'user1_app1', 'permissions': {'configure': '.*', 'write': '.*', 'read': '.*'}}]},
    {'name': '/app2', 'user_permissions': [{'username': 'user1_app2', 'permissions': {'configure': '.*', 'write': '.*', 'read': '.*'}}]}
]

# Create virtual hosts
def create_virtual_host(vhost_name):
    response = requests.put(f"{rabbitmq_url}vhosts/{vhost_name}", auth=HTTPBasicAuth(admin_username, admin_password))
    if response.status_code == 201:
        print(f"Virtual host '{vhost_name}' created successfully.")
    else:
        print(f"Failed to create virtual host '{vhost_name}'. Status code: {response.status_code}")

# Create users and set permissions
def create_user_and_set_permissions(username, vhost, permissions):
    # Create user
    response = requests.put(f"{rabbitmq_url}users/{username}", json={'password': username + '_password', 'tags': ''}, auth=HTTPBasicAuth(admin_username, admin_password))
    if response.status_code == 201:
        print(f"User '{username}' created successfully.")
    else:
        print(f"Failed to create user '{username}'. Status code: {response.status_code}")
        return

    # Set permissions
    response = requests.put(f"{rabbitmq_url}permissions/{vhost}/{username}", json=permissions, auth=HTTPBasicAuth(admin_username, admin_password))
    if response.status_code == 204:
        print(f"Permissions set for user '{username}' on vhost '{vhost}'.")
    else:
        print(f"Failed to set permissions for user '{username}' on vhost '{vhost}'. Status code: {response.status_code}")

# Main execution
for vhost in virtual_hosts:
    create_virtual_host(vhost['name'])
    for user_permission in vhost['user_permissions']:
        create_user_and_set_permissions(user_permission['username'], vhost['name'], user_permission['permissions'])